member.example:
Bind a slider value to a float ViewModel property using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderValueBinder _volume;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private float _volume;
    }


Bind a slider value in code, using TwoWay mode so changes in either direction are propagated.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Slider _volumeSlider;
        
        private SliderValueBinder Volume => new(_volumeSlider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private float _volume;
    }

Bind a slider value to a float ViewModel property using a MonoBinder component assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderValueMonoBinder _volume;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private float _volume;
    }
